class InMemoryAuthStore:
    def __init__(self):
        self._lock = threading.Lock()
        self._users = {
            "alice": self._hash_pw("password123"),
            "bob": self._hash_pw("secret"),
        }
        self._tokens = {}  # token -> (username, expiry_epoch)

    @staticmethod
    def _hash_pw(pw: str) -> str:
        return hashlib.sha256(pw.encode("utf-8")).hexdigest()

    def authenticate(self, username: str, password: str) -> bool:
        with self._lock:
            hpw = self._users.get(username)
            return hpw is not None and hpw == self._hash_pw(password)

    def issue_token(self, username: str, ttl_seconds: int = 3600) -> str:
        token = str(uuid.uuid4())
        expiry = int(time.time()) + int(ttl_seconds)
        with self._lock:
            self._tokens[token] = (username, expiry)
        return token

    def validate(self, token: str):
        now = int(time.time())
        with self._lock:
            entry = self._tokens.get(token)
            if not entry:
                return False, "", "token not found"
            username, expiry = entry
            if now >= expiry:
                del self._tokens[token]
                return False, "", "token expired"
            return True, username, "ok"


