            value = data_store.get_data(username, request.key)
            if value is None:
                return pb2.GetDataResponse(success=False, key=request.key, value_json="", message="key not found")
            return pb2.GetDataResponse(success=True, key=request.key, value_json=json.dumps(value), message="ok")

